import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { useParams, useNavigate, useLocation } from 'react-router-dom';
import { Container, Row, Col, Card, Button, Spinner, Form, ListGroup, Alert, Accordion } from 'react-bootstrap';
import { ArrowLeft, Clock, Calendar, Person, Envelope, Telephone, CheckCircle, Mailbox } from 'react-bootstrap-icons';
import DatePicker from 'react-datepicker';
import 'react-datepicker/dist/react-datepicker.css';
import { publicApi } from '../../services/api';
import { useTheme } from '../../contexts/ThemeContext';

function BookingFlow() {
  const { slug } = useParams();
  const navigate = useNavigate();
  const location = useLocation();
  const { business } = useTheme();

  const services = useMemo(() => location.state?.services || [], [location.state?.services]);
  const totalDuration = services.reduce((sum, s) => sum + s.duracion_minutos, 0);
  const totalPrice = services.reduce((sum, s) => sum + parseFloat(s.precio), 0);

  const [selectedDate, setSelectedDate] = useState(null);
  const [selectedSlot, setSelectedSlot] = useState(null);
  const [slots, setSlots] = useState([]);
  const [loadingSlots, setLoadingSlots] = useState(false);
  const [step, setStep] = useState(1);

  const [formData, setFormData] = useState({
    nombre: '',
    email: '',
    telefono: '',
    notas: '',
  });

  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState('');
  const [bookingResult, setBookingResult] = useState(null);
  const [resendingEmail, setResendingEmail] = useState(false);
  const [resendError, setResendError] = useState('');
  const [resendSuccess, setResendSuccess] = useState('');

  const loadSlots = useCallback(async () => {
    setLoadingSlots(true);
    setSelectedSlot(null);
    try {
      // Fix timezone issue: use local date instead of UTC
      const year = selectedDate.getFullYear();
      const month = String(selectedDate.getMonth() + 1).padStart(2, '0');
      const day = String(selectedDate.getDate()).padStart(2, '0');
      const dateStr = `${year}-${month}-${day}`;

      const serviceIds = services.map(s => s.id);

      console.log('Loading slots:', {
        slug,
        dateStr,
        selectedDate: selectedDate.toString(),
        localDateString: selectedDate.toLocaleDateString(),
        serviceIds,
        services
      });

      // Don't pass employeeId for now - let backend handle it
      const data = await publicApi.getAvailability(slug, dateStr, serviceIds);
      console.log('Slots received:', data);

      setSlots(data.slots || []);
    } catch (err) {
      console.error('Error loading slots:', err);
      setError('Error al cargar disponibilidad');
    } finally {
      setLoadingSlots(false);
    }
  }, [selectedDate, services, slug]);

  useEffect(() => {
    if (services.length === 0) {
      navigate(`/${slug}`);
    }
  }, [services, slug, navigate]);

  useEffect(() => {
    if (selectedDate) {
      loadSlots();
    }
  }, [selectedDate, loadSlots]);

  const handleSubmit = async () => {
    setSubmitting(true);
    setError('');

    // Validate emails match
    if (formData.email !== formData.confirmEmail) {
      setError('Los emails no coinciden. Por favor, verifica ambos campos.');
      setSubmitting(false);
      return;
    }

    // Validate email format
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(formData.email)) {
      setError('Por favor, introduce un email válido.');
      setSubmitting(false);
      return;
    }

    try {
      // Fix timezone issue for booking too
      const year = selectedDate.getFullYear();
      const month = String(selectedDate.getMonth() + 1).padStart(2, '0');
      const day = String(selectedDate.getDate()).padStart(2, '0');
      const dateStr = `${year}-${month}-${day}`;

      const bookingData = {
        serviceIds: services.map(s => s.id),
        date: dateStr,
        startTime: selectedSlot.start,
        client: {
          name: formData.nombre,
          email: formData.email || null,
          phone: formData.telefono || null,
        },
        notes: formData.notas || null,
      };

      console.log('Creating booking:', {
        slug,
        bookingData,
        selectedSlot,
        selectedDate,
        services
      });

      const result = await publicApi.createBooking(slug, bookingData);
      setBookingResult(result);
      setStep(4);
    } catch (err) {
      console.error('Error creating booking:', err);
      setError(err.message || 'Error al crear la reserva');
    } finally {
      setSubmitting(false);
    }
  };

  const handleResendEmail = async () => {
    setResendingEmail(true);
    setResendError('');
    setResendSuccess('');

    try {
      // Use the same date format as in handleSubmit
      const year = selectedDate.getFullYear();
      const month = String(selectedDate.getMonth() + 1).padStart(2, '0');
      const day = String(selectedDate.getDate()).padStart(2, '0');
      const dateStr = `${year}-${month}-${day}`;

      console.log('=== RESEND EMAIL DEBUG ===');
      console.log('Resend email data:', {
        email: formData.email,
        name: formData.nombre,
        date: dateStr,
        startTime: selectedSlot.start,
        originalDate: selectedDate,
        dateStr,
        selectedSlot,
        formData
      });
      console.log('==========================');

      await publicApi.resendConfirmation({
        email: formData.email,
        name: formData.nombre,
        date: dateStr,
        startTime: selectedSlot.start
      });

      setResendSuccess('Email de confirmación reenviado correctamente. Revisa tu bandeja de entrada.');
    } catch (err) {
      console.error('Error resending email:', err);
      setResendError(err.message || 'Error al reenviar el email de confirmación');
    } finally {
      setResendingEmail(false);
    }
  };

  if (services.length === 0) return null;

  return (
    <Container className="py-4">
      <Button variant="outline-secondary" className="mb-4" onClick={() => step > 1 ? setStep(step - 1) : navigate(`/${slug}`)}>
        <ArrowLeft className="me-2" /> {step > 1 ? 'Anterior' : 'Volver'}
      </Button>

      {/* Progress */}
      <div className="d-flex justify-content-center mb-4">
        {[1, 2, 3].map((s) => (
          <div
            key={s}
            className="mx-2 rounded-circle d-flex align-items-center justify-content-center"
            style={{
              width: 40,
              height: 40,
              backgroundColor: s <= step ? (business?.color_primario || '#3B82F6') : '#e9ecef',
              color: s <= step ? 'white' : '#6c757d',
            }}
          >
            {s === 1 ? <Calendar size={18} /> : s === 2 ? <Clock size={18} /> : <Person size={18} />}
          </div>
        ))}
      </div>

      {error && <Alert variant="danger" className="mb-4">{error}</Alert>}

      {/* Step 1: Date Selection */}
      {step === 1 && (
        <>
          <h4 className="mb-3">1. Selecciona una fecha</h4>
          <Row className="justify-content-center">
            <Col md={6} className="text-center">
              <DatePicker
                selected={selectedDate}
                onChange={setSelectedDate}
                minDate={new Date()}
                inline
                className="form-control"
              />
              <Button
                variant="primary"
                className="mt-3 w-100"
                disabled={!selectedDate}
                onClick={() => setStep(2)}
              >
                Continuar
              </Button>
            </Col>
          </Row>
        </>
      )}

      {/* Step 2: Time Selection */}
      {step === 2 && (
        <>
          <h4 className="mb-3">2. Selecciona horario</h4>
          <p className="text-muted mb-3">
            {selectedDate?.toLocaleDateString('es-ES', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}
          </p>

          {loadingSlots ? (
            <div className="text-center py-5">
              <Spinner animation="border" />
            </div>
          ) : slots.length === 0 ? (
            <Alert variant="info">No hay disponibilidad para esta fecha. Prueba con otra fecha.</Alert>
          ) : (
            <Row>
              {slots.map((slot) => (
                <Col key={slot.start} xs={6} md={4} lg={3} className="mb-3">
                  <Card
                    className={`cursor-pointer text-center ${selectedSlot?.start === slot.start ? 'border-primary border-2' : ''}`}
                    onClick={() => setSelectedSlot(slot)}
                  >
                    <Card.Body>
                      <h5 className="mb-0">{slot.start}</h5>
                      <small className="text-muted">{slot.durationMinutes} min</small>
                    </Card.Body>
                  </Card>
                </Col>
              ))}
            </Row>
          )}

          <Button
            variant="primary"
            className="mt-3"
            disabled={!selectedSlot}
            onClick={() => setStep(3)}
          >
            Continuar
          </Button>
        </>
      )}

      {/* Step 3: Customer Data */}
      {step === 3 && (
        <>
          <h4 className="mb-3">3. Tus datos</h4>
          <Row>
            <Col md={6}>
              <Form>
                <Form.Group className="mb-3">
                  <Form.Label><Person className="me-2" />Nombre completo *</Form.Label>
                  <Form.Control
                    type="text"
                    value={formData.nombre}
                    onChange={(e) => setFormData({...formData, nombre: e.target.value})}
                    required
                  />
                </Form.Group>

                <Form.Group className="mb-3">
                  <Form.Label><Envelope className="me-2" />Email *</Form.Label>
                  <Form.Control
                    type="email"
                    value={formData.email}
                    onChange={(e) => setFormData({...formData, email: e.target.value})}
                    onBlur={(e) => {
                      const email = e.target.value;
                      const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
                      if (!emailRegex.test(email)) {
                        e.target.setCustomValidity('Por favor, introduce un email válido');
                      } else {
                        e.target.setCustomValidity('');
                      }
                    }}
                    onInput={(e) => e.target.setCustomValidity('')}
                    required
                    placeholder="ejemplo@correo.com"
                  />
                  <Form.Text className="text-muted">
                    Verifica que tu email sea correcto. No recibirás confirmación si hay un error.
                  </Form.Text>
                </Form.Group>

                <Form.Group className="mb-3">
                  <Form.Label><Envelope className="me-2" />Confirmar Email *</Form.Label>
                  <Form.Control
                    type="email"
                    value={formData.confirmEmail || ''}
                    onChange={(e) => setFormData({...formData, confirmEmail: e.target.value})}
                    onBlur={(e) => {
                      if (e.target.value !== formData.email) {
                        e.target.setCustomValidity('Los emails no coinciden');
                      } else {
                        e.target.setCustomValidity('');
                      }
                    }}
                    onInput={(e) => e.target.setCustomValidity('')}
                    required
                    placeholder="Repite tu email"
                  />
                  <Form.Text className="text-muted">
                    Confirma tu email para evitar errores.
                  </Form.Text>
                </Form.Group>

                <Form.Group className="mb-3">
                  <Form.Label><Telephone className="me-2" />Teléfono</Form.Label>
                  <Form.Control
                    type="tel"
                    value={formData.telefono}
                    onChange={(e) => setFormData({...formData, telefono: e.target.value})}
                  />
                </Form.Group>

                <Form.Group className="mb-3">
                  <Form.Label>Notas adicionales</Form.Label>
                  <Form.Control
                    as="textarea"
                    rows={3}
                    value={formData.notas}
                    onChange={(e) => setFormData({...formData, notas: e.target.value})}
                  />
                </Form.Group>
              </Form>
            </Col>

            <Col md={6}>
              <Card className="mb-3">
                <Card.Body>
                  <h6 className="fw-bold mb-3">Resumen de tu cita</h6>
                  <ListGroup variant="flush">
                    {services.map(s => (
                      <ListGroup.Item key={s.id} className="px-0 d-flex justify-content-between">
                        <span>{s.nombre}</span>
                        <span>{parseFloat(s.precio).toFixed(2)}€</span>
                      </ListGroup.Item>
                    ))}
                  </ListGroup>
                  <hr />
                  <div className="d-flex justify-content-between mb-2">
                    <span><Clock className="me-2" />{totalDuration} min</span>
                  </div>
                  <div className="d-flex justify-content-between mb-2">
                    <span><Calendar className="me-2" />{selectedDate?.toLocaleDateString()}</span>
                  </div>
                  <div className="d-flex justify-content-between mb-2">
                    <span><Clock className="me-2" />{selectedSlot?.start}</span>
                  </div>
                  <hr />
                  <div className="d-flex justify-content-between">
                    <span className="fw-bold">Total:</span>
                    <span className="fw-bold fs-5">{totalPrice.toFixed(2)}€</span>
                  </div>
                </Card.Body>
              </Card>

              <Button
                variant="primary"
                className="w-100"
                disabled={!formData.nombre || !formData.email || submitting}
                onClick={handleSubmit}
              >
                {submitting ? (
                  <><Spinner as="span" size="sm" className="me-2" />Reservando...</>
                ) : (
                  'Confirmar reserva'
                )}
              </Button>
            </Col>
          </Row>
        </>
      )}

      {/* Step 4: Success */}
      {step === 4 && bookingResult && (
        <div className="text-center py-5">
          <CheckCircle size={80} className="text-success mb-4" />
          <h3 className="fw-bold mb-3">¡Reserva creada!</h3>
          <p className="text-muted mb-4">
            Hemos enviado un email a <strong>{formData.email}</strong> con los detalles.
            <br />
            Revisa tu bandeja de entrada y confirma tu cita.
          </p>

          {/* Email verification warning */}
          <Alert variant="warning" className="mb-4 d-inline-block text-start">
            <Alert.Heading className="h6">⚠️ ¿Es correcto tu email?</Alert.Heading>
            <p className="mb-2">
              Si te has equivocado al introducir tu dirección de correo, <strong>no recibirás el email de confirmación</strong> y tu reserva podría ser cancelada automáticamente.
            </p>
            <div className="d-flex gap-2 mt-3">
              <Button 
                variant="outline-primary" 
                size="sm"
                onClick={handleResendEmail}
                disabled={resendingEmail}
                className="me-2"
              >
                {resendingEmail ? (
                  <><Spinner as="span" size="sm" className="me-2" />Reenviando...</>
                ) : (
                  <><Mailbox className="me-2" size={16} />Reenviar email de confirmación</>
                )}
              </Button>
              <Button variant="outline-secondary" size="sm" onClick={() => navigate('/')}>
                <ArrowLeft className="me-2" size={16} />Volver al inicio
              </Button>
            </div>
            {resendError && (
              <Alert variant="danger" className="mt-2 mb-0">
                <small>{resendError}</small>
              </Alert>
            )}
            {resendSuccess && (
              <Alert variant="success" className="mt-2 mb-0">
                <small>{resendSuccess}</small>
              </Alert>
            )}
          </Alert>

          <div>
            <Button variant="primary" onClick={() => navigate('/')}>
              Volver al inicio
            </Button>
          </div>
        </div>
      )}
    </Container>
  );
}

export default BookingFlow;
